INSERT INTO `page_layout_assignments` (`id`, `role_id`, `object_record_type_id`, `object_state_id`, `page_layout_id`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `allow_enter_mini_layout`) VALUES ('c3f34316-8f66-4cf7-b74d-10b111589400', 'bfb15d2f-b600-11ea-aab5-0215c63fce1a', 'e7b29cc6-e05c-11ea-bc49-0215c63fce1a', 'f3f66e1d-14e0-4527-8bae-b72c1f15ef31', 'e7b29e8c-e05c-11ea-bc49-0215c63fce1a', '0', '1', now(), '1', now(), '1'); 
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('4ef57ae1-e537-11e7-9372-186590dcd3c9', '87d3c319-598a-4fe2-b391-21b8bbcae4c7', '会议费用校验', '餐费和住宿费校验', 'trigger', 'from orionbase.common import models\nfrom decimal import Decimal\n\nif isinstance(instance, models.Events):\n    event = instance\nelse:\n    event = instance.event\n\n# 费用类型\nexpense_type = models.ObjectRecordTypes.objects.get(id=instance.record_type_id)\n\n\nclass ExpenseChecker(object):\n    @classmethod\n    def _avg(self, divisor, dividend):\n        return round(Decimal(divisor) / Decimal(dividend), 2)\n\n    @classmethod\n    def _sum(self, divisor, dividend):\n        return round(Decimal(divisor) * Decimal(dividend), 2)\n\n\n# 会议类型名称\n# event_record_type_name = event.record_type.name\nif expense_type.name in (\'hotel_fee\', \'meal_fee\'):\n    # 报告阶段会议，单价=金额/人数\n    # if \'_report\' in event_record_type_name:\n    if event.record_type.name.endswith(\'__report\'):\n        if instance.total_expense and instance.number_1:\n            avg_expense = ExpenseChecker._avg(instance.total_expense, instance.number_1)\n            instance.number_2 = avg_expense\n        elif instance.total_expense and not instance.number_1:\n            error_message = u\'单价为必填项;\'\n            raise create_validation_trigger_rule_errors(error_message)\n        elif instance.number_1 and not instance.total_expense:\n            error_message = u\'金额为必填项;\'\n            raise create_validation_trigger_rule_errors(error_message)\n        else:\n            pass\n    # 计划阶段会议，金额=单价*人数\n    else:\n        if instance.number_1 and instance.number_2:\n            sum_expense = ExpenseChecker._sum(instance.number_1, instance.number_2)\n            instance.total_expense = sum_expense\n        elif instance.number_2 and not instance.number_1:\n            error_message = u\'人数为必填项;\'\n            raise create_validation_trigger_rule_errors(error_message)\n        elif instance.number_1 and not instance.number_2:\n            error_message = u\'单价为必填项;\'\n            raise create_validation_trigger_rule_errors(error_message)\n        else:\n            pass', '', '0', '1', '2019-06-24 11:07:03', '1', '2020-08-18 08:51:04', 'pre_save', '1', 'custom', 'event_expense_validation', '1');
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('3ab786ab-e144-11ea-bc49-0215c63fce1a', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '会议费用校验', '会议费用校验', 'trigger', 'from orionbase.common import models\nfrom decimal import Decimal\nfrom django.db.models import Q, Sum, F, FloatField\n\n\nif instance and instance.state.name == \'sent_approval\':\n    # 会议类型\n    event_record_type = models.ObjectRecordTypes.objects.get(id=instance.record_type_id)\n    a_tier = {u\'北京\', u\'上海\', u\'广州\', u\'北京市\', u\'上海市\', u\'广州市\'}\n    notification_msg = \'\'\n    git_expense_record_type = [\'cs_training_fee\']\n    event_expense_reord_type = [\'hotel_fee\', \'meal_fee\', \'communication_expense\',\n                                \'cs_other\', \'cs_rent_facility\', \'cs_rent_expense\', \'cs_three_expense\']\n\n    event_expense = models.EventExpenses.objects.filter(event_id=instance.id,\n                                                        record_type__name__in=event_expense_reord_type, deleted=0,\n                                                        total_expense__isnull=False).values_list(\n         \'record_type__name\', \'record_type__label\', \'total_expense\',\'number_1\', \'number_2\')\n\n    class ExpenseChecker(object):\n        error_msg = u\'费用信息填写有误，请检查\'\n        @classmethod\n        def _check_count(cls, num):\n            if num is None:\n                return False\n            if int(num) <= 0:\n                return False\n            return True\n\n        @classmethod\n        def _avg(cls, divisor, dividend):\n            return round(Decimal(divisor) / Decimal(dividend))\n\n        @classmethod\n        def _check_limit(cls, price, limit, msg):\n            if price > limit:\n                msg += u\'，超越上限{}元\'.format(limit)\n            return msg\n\n        @classmethod\n        def add_msg(cls, msg, expense, count, limit):\n            if cls._check_count(count):\n                avg_expense = cls._avg(expense, count)\n                msg += u\'人均费用{}元\'.format(avg_expense)\n                msg = cls._check_limit(avg_expense, limit, msg)\n            else:\n                msg = cls.error_msg\n            return msg\n    city = models.Events.advance_objects.filter(geography_id=instance.geography).values_list(\'geography__city\', flat=True)\n    city = city[0] if city else None\n    # 城市会\n    if event_record_type in (\'d9536480-5eed-11e6-8920-5cc5d4d378cb\', \'a2ae2ac5-c93a-4fcf-8834-e3592fe4ad48\'):\n        for event_expense_record_type_name, event_expense_record_type_label, \\\n            total_expense, number_1, number_2 in event_expense:\n            if event_expense_record_type_name in (\'meal_fee\'):\n                notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense, number_1, 300)\n                raise create_validation_trigger_rule_errors(notification_msg)\n            elif event_expense_record_type_name in (\'hotel_fee\'):\n                if city in a_tier:\n                    notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense,number_1, 1500)\n                    raise create_validation_trigger_rule_errors(notification_msg)\n                else:\n                    notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense,number_1, 1200)\n                    raise create_validation_trigger_rule_errors(notification_msg)\n    # 科室会\n    elif event_record_type in (\'05320400-e35f-11e9-b9aa-0298a739dec0\', \'21f2482f-e35f-11e9-b9aa-0298a739dec0\'):\n        for event_expense_record_type_name, event_expense_record_type_label, \\\n            total_expense, number_1, number_2 in event_expense:\n            if event_expense_record_type_name in (\'meal_fee\'):\n                notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense, number_1, 200)\n                raise create_validation_trigger_rule_errors(notification_msg)\n    # 市场部会议\n    elif event_record_type in (\'bdf5191c-efe8-11e9-b9aa-0298a739dec0\', \'05b19885-efe9-11e9-b9aa-0298a739dec0\'):\n        for event_expense_record_type_name, event_expense_record_type_label, \\\n            total_expense, number_1, number_2 in event_expense:\n            if event_expense_record_type_name in (\'hotel_fee\'):\n                if city in a_tier:\n                    notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense, number_1, 1500)\n                    raise create_validation_trigger_rule_errors(notification_msg)\n                else:\n                    notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense, number_1, 1200)\n                    raise create_validation_trigger_rule_errors(notification_msg)\n            elif event_expense_record_type_name in (\'meal_fee\'):\n                if instance.picklist_1 == \'0531e159-1e4d-44f5-8970-fffc0f1e5597\':\n                    notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense, number_1, 100)\n                    raise create_validation_trigger_rule_errors(notification_msg)\n                else:\n                    notification_msg = ExpenseChecker.add_msg(notification_msg, total_expense, number_1, 500)\n                    raise create_validation_trigger_rule_errors(notification_msg)', '', '0', '1', '2019-06-24 11:08:42', '1', '2020-08-18 08:53:54', 'pre_save', '1', 'custom', 'event_expense', '1');
